#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int X, Y, Z; scanf("%d %d %d", &X, &Y, &Z);
        if(X < Y && X < Z) printf("ALICE\n");
        else if(Y < X && Y < Z) printf("BOB\n");
        else printf("CHARLIE\n");
    }
    return 0;
}

