import sys

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    t = int(data[0])
    idx = 1
    out = []
    for _ in range(t):
        x = int(data[idx]); y = int(data[idx+1]); z = int(data[idx+2]); idx += 3
        if x < y and x < z:
            out.append('ALICE')
        elif y < x and y < z:
            out.append('BOB')
        else:
            out.append('CHARLIE')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

